+type Conversation = {
+  id: string;
+  kind: "direct" | "channel";
+  title?: string;
+};
+
+type Thread = {
+  id: string;
+  conversationId: string;
+  title: string;
+};
+
+type Message = {
+  id: string;
+  direction: "inbound" | "outbound";
+  conversation: Conversation;
+  senderId: string;
+  senderName?: string;
+  text: string;
+  timestamp: number;
+  threadId?: string;
+  threadTitle?: string;
+  deleted?: boolean;
+  editedAt?: number;
+  reactions: Array<{ emoji: string; senderId: string }>;
+};
+
+type BusEvent =
+  | { cursor: number; kind: "thread-created"; thread: Thread }
+  | { cursor: number; kind: string; message?: Message; emoji?: string };
+
+type Snapshot = {
+  conversations: Conversation[];
+  threads: Thread[];
+  messages: Message[];
+  events: BusEvent[];
+};
+
+type ReportEnvelope = {
+  report: null | {
+    outputPath: string;
+    markdown: string;
+    generatedAt: string;
+  };
+};
+
+type Bootstrap = {
+  baseUrl: string;
+  latestReport: ReportEnvelope["report"];
+  defaults: {
+    conversationKind: "direct" | "channel";
+    conversationId: string;
+    senderId: string;
+    senderName: string;
+  };
+};
+
+type UiState = {
+  bootstrap: Bootstrap | null;
+  snapshot: Snapshot | null;
+  latestReport: ReportEnvelope["report"];
+  selectedConversationId: string | null;
+  selectedThreadId: string | null;
+  composer: {
+    conversationKind: "direct" | "channel";
+    conversationId: string;
+    senderId: string;
+    senderName: string;
+    text: string;
+  };
+  busy: boolean;
+  error: string | null;
+};
+
+async function getJson<T>(path: string): Promise<T> {
+  const response = await fetch(path);
+  if (!response.ok) {
+    throw new Error(`${response.status} ${response.statusText}`);
+  }
+  return (await response.json()) as T;
+}
+
+async function postJson<T>(path: string, body: unknown): Promise<T> {
+  const response = await fetch(path, {
+    method: "POST",
+    headers: {
+      "content-type": "application/json",
+    },
+    body: JSON.stringify(body),
+  });
+  if (!response.ok) {
+    const payload = (await response.json().catch(() => ({}))) as { error?: string };
+    throw new Error(payload.error || `${response.status} ${response.statusText}`);
+  }
+  return (await response.json()) as T;
+}
+
+function formatTime(timestamp: number) {
+  return new Date(timestamp).toLocaleTimeString([], {
+    hour: "2-digit",
+    minute: "2-digit",
+    second: "2-digit",
+  });
+}
+
+function escapeHtml(text: string) {
+  return text
+    .replaceAll("&", "&amp;")
+    .replaceAll("<", "&lt;")
+    .replaceAll(">", "&gt;")
+    .replaceAll('"', "&quot;");
+}
+
+function filteredMessages(state: UiState) {
+  const messages = state.snapshot?.messages ?? [];
+  return messages.filter((message) => {
+    if (state.selectedConversationId && message.conversation.id !== state.selectedConversationId) {
+      return false;
+    }
+    if (state.selectedThreadId && message.threadId !== state.selectedThreadId) {
+      return false;
+    }
+    return true;
+  });
+}
+
+function deriveSelectedConversation(state: UiState): string | null {
+  if (state.selectedConversationId) {
+    return state.selectedConversationId;
+  }
+  return state.snapshot?.conversations[0]?.id ?? null;
+}
+
+function deriveSelectedThread(state: UiState): string | null {
+  if (state.selectedThreadId) {
+    return state.selectedThreadId;
+  }
+  return null;
+}
